class Solution:
    def countWordOccurrences(self, chunks, queries):
        s = ''.join(chunks)
        n = len(s)

        def is_letter(ch):
            return 'a' <= ch <= 'z'

        counts = {}
        i = 0
        while i < n:
            if is_letter(s[i]):
                j = i
                while j < n and (is_letter(s[j]) or (s[j] == '-' and 0 < j < n - 1 and is_letter(s[j - 1]) and is_letter(s[j + 1]))):
                    j += 1
                word = s[i:j]
                counts[word] = counts.get(word, 0) + 1
                i = j
            else:
                i += 1
        return [counts.get(q, 0) for q in queries]

